## Generated by Anna with the help of ChatGPT.
## Expect to get 31 top-level pathways.
## Requires requests module

#!/usr/bin/env python3
import os
import re
import time
from pathlib import Path
import requests
import sys

## Use the Reactome RESTful API BioPax exporter.
CONTENT = "https://reactome.org/ContentService"
BIOPAX_L3 = "https://reactome.org/ReactomeRESTfulAPI/RESTfulWS/biopaxExporter/Level3"

# Stable Identified for Signal Transduction (human)
# https://reactome.org/PathwayBrowser/#/R-HSA-162582
SIGNAL_TRANSDUCTION_STID = "R-HSA-162582"  

OUTDIR = Path("../raw/")
OUTDIR.mkdir(parents=True, exist_ok=True)

session = requests.Session()
session.headers.update({"User-Agent": "reactome-biopax-downloader/1.0"})

def safe_filename(name: str) -> str:
    name = re.sub(r"[^\w\-\. ]+", "", name).strip()
    name = re.sub(r"\s+", "_", name)
    return name[:180] if len(name) > 180 else name

def get_json(url: str):
    r = session.get(url, timeout=60)
    r.raise_for_status()
    return r.json()

def get_contained_events(stid: str):
    # Reactome endpoint: /ContentService/data/pathway/{id}/containedEvents
    url = f"{CONTENT}/data/pathway/{stid}/containedEvents"
    return get_json(url)

def ensure_dbid(event_obj: dict) -> int:
    # Many endpoints include dbId already; if not, resolve via /data/query/{id}
    dbid = event_obj.get("dbId")
    if isinstance(dbid, int):
        return dbid

    stid = event_obj.get("stId") or event_obj.get("stID") or event_obj.get("stableIdentifier")
    if not stid:
        raise ValueError(f"Cannot resolve dbId; missing stable id in object: {event_obj.keys()}")

    q = get_json(f"{CONTENT}/data/query/{stid}")
    dbid = q.get("dbId")
    if not isinstance(dbid, int):
        raise ValueError(f"Query did not return numeric dbId for {stid}: {dbid}")
    return dbid

def download_biopax_level3(dbid: int, outpath: Path):
    url = f"{BIOPAX_L3}/{dbid}"
    with session.get(url, stream=True, timeout=180) as r:
        r.raise_for_status()
        outpath_tmp = outpath.with_suffix(outpath.suffix + ".part")
        with open(outpath_tmp, "wb") as f:
            for chunk in r.iter_content(chunk_size=1024 * 1024):
                if chunk:
                    f.write(chunk)
        outpath_tmp.replace(outpath)

def get_pathway_list():
    #Reactome Endpoint: "{CONTENT}/data/query/{SIGNAL_TRANSDUCTION_STID}"
    url = f"{CONTENT}/data/query/{SIGNAL_TRANSDUCTION_STID}"
    j = requests.get(url, headers={"Accept": "application/json"}).json()

    # Only get immediate children of the SIGNAL_TRANSDUCTION_STID
    children = []
    for ev in j.get("hasEvent", []):
        # entries typically include dbId + displayName + stId (or may be resolvable via /data/query/<stId>)
        print((ev.get("stId"), ev.get("displayName"), ev.get("dbId")))
        children.append(ev)

    print("Number of Pathways:", len(children))
    return children

def main():
    # get list of pathways
    pathways = get_pathway_list()

    for i, p in enumerate(pathways):
        stid = p.get("stId", "UNKNOWN")
        name = p.get("displayName") or p.get("name") or stid
        dbid = ensure_dbid(p)

        fname = f"{stid}__{safe_filename(name)}.owl"
        outpath = OUTDIR / fname

        if outpath.exists() and outpath.stat().st_size > 0:
            print(f"[{i}/{len(pathways)}] SKIP (exists): {fname}")
            continue

        print(f"[{i}/{len(pathways)}] Downloading BioPAX L3: {stid} (dbId={dbid})")
        download_biopax_level3(dbid, outpath)

        # Be polite to the API
        time.sleep(0.2)

    print(f"Done. Files saved to: {OUTDIR.resolve()}")
    sys.exit()

if __name__ == "__main__":
    main()
